48	function loadCheckpoint() {
49	  if (FRESH || !existsSync(CHECKPOINT)) return { acts: {}, sessionId: null, facts: {} };
50	  try {
51	    const cp = JSON.parse(readFileSync(CHECKPOINT, 'utf8'));
52	    cp.acts ??= {};
53	    cp.facts ??= {};
54	    return cp;
55	  } catch {
56	    return { acts: {}, sessionId: null, facts: {} };
57	  }
