  const huch = await grepFs(pod, /Huchuypicchu/i, new RegExp(`^${PROJECT}/`));
  report.check(
    'the PDF fixture\'s unique token "Huchuypicchu" landed in a real project/space FILE (⇒ the PDF was READ, not guessed)',
